-- MobilNiaga Enterprise Multi-Company
-- Semua database dibuat terpisah agar sesuai konsep database-per-service.
SET FOREIGN_KEY_CHECKS=0;
DROP DATABASE IF EXISTS mobilniaga_master;
DROP DATABASE IF EXISTS payment_gateway_db;
DROP DATABASE IF EXISTS delivery_gateway_db;

DROP DATABASE IF EXISTS seller_auto2000_db;
DROP DATABASE IF EXISTS seller_honda_db;
DROP DATABASE IF EXISTS seller_mitsubishi_db;
DROP DATABASE IF EXISTS seller_hyundai_db;
DROP DATABASE IF EXISTS seller_suzuki_db;
DROP DATABASE IF EXISTS seller_wuling_db;

CREATE DATABASE mobilniaga_master CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
CREATE DATABASE payment_gateway_db CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
CREATE DATABASE delivery_gateway_db CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE mobilniaga_master;
CREATE TABLE partners(
  partner_code VARCHAR(40) PRIMARY KEY,
  partner_name VARCHAR(160), partner_type VARCHAR(40), db_name VARCHAR(80), api_base_url VARCHAR(255), city VARCHAR(80), status VARCHAR(20), brand_color VARCHAR(20)
);
CREATE TABLE customers(
  customer_global_id VARCHAR(40) PRIMARY KEY, full_name VARCHAR(120), phone VARCHAR(40), email VARCHAR(120) UNIQUE, password VARCHAR(80), city VARCHAR(80), address TEXT, created_at DATETIME
);
CREATE TABLE marketplace_products(
  listing_id VARCHAR(50) PRIMARY KEY, seller_code VARCHAR(40), external_vehicle_code VARCHAR(50), brand VARCHAR(60), model VARCHAR(140), vehicle_type VARCHAR(60), year INT, fuel_type VARCHAR(40), transmission VARCHAR(40), price BIGINT, unit_cost BIGINT, stock_snapshot INT, image_path VARCHAR(255), rating DECIMAL(3,1), description TEXT, status VARCHAR(20)
);
CREATE TABLE orders(
  order_global_id VARCHAR(60) PRIMARY KEY, customer_global_id VARCHAR(40), buyer_name VARCHAR(120), seller_code VARCHAR(40), listing_id VARCHAR(50), vehicle_code VARCHAR(50), qty INT, subtotal BIGINT, shipping_fee BIGINT, discount_amount BIGINT, grand_total BIGINT, payment_method VARCHAR(60), payment_status VARCHAR(30), order_status VARCHAR(30), shipment_status VARCHAR(30), destination_city VARCHAR(80), created_at DATETIME
);
CREATE TABLE order_status_history(history_id INT AUTO_INCREMENT PRIMARY KEY, order_global_id VARCHAR(60), status VARCHAR(40), note VARCHAR(255), created_at DATETIME);
CREATE TABLE payments_summary(payment_summary_id INT AUTO_INCREMENT PRIMARY KEY, order_global_id VARCHAR(60), provider_code VARCHAR(40), provider_name VARCHAR(120), payment_reference VARCHAR(80), amount BIGINT, payment_status VARCHAR(30), paid_at DATETIME);
CREATE TABLE shipments_summary(shipment_summary_id INT AUTO_INCREMENT PRIMARY KEY, order_global_id VARCHAR(60), delivery_code VARCHAR(40), delivery_name VARCHAR(120), tracking_number VARCHAR(80), destination_city VARCHAR(80), shipment_status VARCHAR(40), current_location VARCHAR(120), estimated_arrival DATE, updated_at DATETIME);
CREATE TABLE settlements(settlement_id VARCHAR(60) PRIMARY KEY, order_global_id VARCHAR(60), seller_code VARCHAR(40), provider_code VARCHAR(40), gross_amount BIGINT, marketplace_fee BIGINT, seller_net_amount BIGINT, settlement_status VARCHAR(30), created_at DATETIME);
CREATE TABLE api_logs(log_id INT AUTO_INCREMENT PRIMARY KEY, service_name VARCHAR(120), endpoint VARCHAR(120), method VARCHAR(12), status_code INT, message VARCHAR(255), created_at DATETIME);

CREATE DATABASE seller_auto2000_db CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE seller_auto2000_db;

CREATE TABLE seller_profile(seller_code VARCHAR(40) PRIMARY KEY, seller_name VARCHAR(160), city VARCHAR(80), pin_code VARCHAR(40), status VARCHAR(20), hero_text TEXT, brand_color VARCHAR(20));
CREATE TABLE vehicles(vehicle_code VARCHAR(50) PRIMARY KEY, seller_code VARCHAR(40), brand VARCHAR(60), model VARCHAR(140), vehicle_type VARCHAR(60), year INT, fuel_type VARCHAR(40), transmission VARCHAR(40), selling_price BIGINT, unit_cost BIGINT, image_path VARCHAR(255), status VARCHAR(20));
CREATE TABLE seller_inventory(inventory_id INT AUTO_INCREMENT PRIMARY KEY, vehicle_code VARCHAR(50), stock_available INT, reserved_stock INT DEFAULT 0, warehouse VARCHAR(120), last_updated TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE seller_orders(seller_order_id INT AUTO_INCREMENT PRIMARY KEY, seller_order_global_id VARCHAR(60), marketplace_order_global_id VARCHAR(60), customer_global_id VARCHAR(40), customer_name VARCHAR(120), vehicle_code VARCHAR(50), qty INT, revenue BIGINT, unit_cost BIGINT, gross_profit BIGINT, order_status VARCHAR(40), shipment_status VARCHAR(40), created_at DATETIME);
CREATE TABLE seller_customers(customer_id INT AUTO_INCREMENT PRIMARY KEY, customer_global_id VARCHAR(40), customer_name VARCHAR(120), phone VARCHAR(40), city VARCHAR(80), total_spend BIGINT DEFAULT 0);
CREATE TABLE sales_recap(recap_id INT AUTO_INCREMENT PRIMARY KEY, recap_date DATE, vehicle_code VARCHAR(50), qty_sold INT, revenue BIGINT, cost BIGINT, gross_profit BIGINT);
CREATE TABLE restock_requests(restock_id VARCHAR(60) PRIMARY KEY, supplier_code VARCHAR(40), vehicle_code VARCHAR(50), qty INT, status VARCHAR(30), requested_at DATETIME);
CREATE TABLE seller_api_logs(log_id INT AUTO_INCREMENT PRIMARY KEY, endpoint VARCHAR(120), method VARCHAR(12), status_code INT, message VARCHAR(255), created_at DATETIME);

