USE payment_gateway_db;
CREATE TABLE payment_providers(provider_code VARCHAR(40) PRIMARY KEY, provider_name VARCHAR(120), provider_type VARCHAR(80), status VARCHAR(20), brand_color VARCHAR(20));
CREATE TABLE payment_transactions(transaction_id INT AUTO_INCREMENT PRIMARY KEY, transaction_global_id VARCHAR(80), order_global_id VARCHAR(80), provider_code VARCHAR(40), customer_name VARCHAR(120), amount BIGINT, fee BIGINT, net_amount BIGINT, payment_status VARCHAR(30), risk_score INT, payment_channel VARCHAR(40), virtual_account VARCHAR(80), qris_code VARCHAR(120), customer_instruction TEXT, expires_at DATETIME, created_at DATETIME);
CREATE TABLE provider_settlements(settlement_id VARCHAR(60) PRIMARY KEY, provider_code VARCHAR(40), seller_code VARCHAR(40), gross_amount BIGINT, fee_amount BIGINT, net_settlement BIGINT, status VARCHAR(30), created_at DATETIME);
CREATE TABLE refunds(refund_id VARCHAR(60) PRIMARY KEY, order_global_id VARCHAR(80), provider_code VARCHAR(40), amount BIGINT, status VARCHAR(30), created_at DATETIME);
CREATE TABLE payment_logs(log_id INT AUTO_INCREMENT PRIMARY KEY, provider_code VARCHAR(40), endpoint VARCHAR(120), status_code INT, message VARCHAR(255), created_at DATETIME);


USE delivery_gateway_db;
CREATE TABLE delivery_partners(delivery_code VARCHAR(40) PRIMARY KEY, delivery_name VARCHAR(120), service_type VARCHAR(80), status VARCHAR(20), brand_color VARCHAR(20));
CREATE TABLE delivery_shipments(shipment_id INT AUTO_INCREMENT PRIMARY KEY, shipment_global_id VARCHAR(80), order_global_id VARCHAR(80), delivery_code VARCHAR(40), buyer_name VARCHAR(120), origin_city VARCHAR(80), destination_city VARCHAR(80), tracking_number VARCHAR(80), shipment_status VARCHAR(40), current_location VARCHAR(120), estimated_arrival DATE, created_at DATETIME);
CREATE TABLE tracking_events(event_id INT AUTO_INCREMENT PRIMARY KEY, tracking_number VARCHAR(80), status VARCHAR(40), location VARCHAR(120), note VARCHAR(255), created_at DATETIME);
CREATE TABLE delivery_logs(log_id INT AUTO_INCREMENT PRIMARY KEY, delivery_code VARCHAR(40), endpoint VARCHAR(120), status_code INT, message VARCHAR(255), created_at DATETIME);


